import { useState, useEffect, useMemo } from 'react';
import {
    Table,
    Button,
    Space,
    message,
    Modal,
    Form,
    Input,
    InputNumber,
    Select,
    Tag,
    List,
    Card,
    Typography,
    Drawer,
    Upload,
    Checkbox,
    Image as AntImage,
    Row,
    Col,
    Empty,
    Popover,
    Alert,
    Steps,
} from 'antd';


import {
    EditOutlined,
    ArrowLeftOutlined,
    PlusOutlined,
    UploadOutlined,
    DownloadOutlined,
    BookOutlined,
    TranslationOutlined,
    ClockCircleOutlined,
    PlusCircleOutlined,
    DeleteOutlined,
    RobotOutlined,
    InboxOutlined,
    BulbOutlined,
    CheckCircleOutlined,
} from '@ant-design/icons';
import { useParams, useNavigate, useOutletContext } from 'react-router-dom';
import type { ColumnsType } from 'antd/es/table';
// import type { RcFile } from 'antd/es/upload/interface'; // Removed unused import
import ReactQuill from 'react-quill-new';
import 'quill/dist/quill.snow.css';
// @ts-ignore
import * as XLSX from 'xlsx';

import CreatePart6Modal from '../components/CreatePart6Modal';
import CreatePart7Modal from '../components/CreatePart7Modal';
import CreatePart1Modal from '../components/CreatePart1Modal';
import EditPart1Modal from '../components/EditPart1Modal';
import CreatePart2BulkModal from '../components/CreatePart2BulkModal'; // Changed from CreatePart2Modal
import CreatePart3Modal from '../components/CreatePart3Modal';
import CreatePart5BulkModal from '../components/CreatePart5BulkModal';
import AudioPlayer from '../components/AudioPlayer';
import { uploadApi, partApi, questionApi, aiApi } from '../services/api';
import type { FormInstance } from 'antd';

// --- Interfaces ---
interface User {
    id?: string;
    role: 'ADMIN' | 'SPECIALIST' | 'TEACHER';
}

interface VocabularyItem {
    word?: string;
    text?: string;
    meaning: string;
    ipa?: string;
    type?: string;
}

interface AIItem {
    en: string;
    vi: string;
}

interface AIPassage {
    label?: string;
    items?: AIItem[];
    sentences?: AIItem[];
}

interface AIQuestionInfo {
    questionNumber: number;
    analysis?: string;
    evidence?: string;
}

interface PassageGroup {
    passage: string;
    audioUrl?: string;
    questions: Question[];
}

interface Question {
    id: string;
    questionNumber: number;
    questionText?: string;
    imageUrl?: string; // Add imageUrl
    audioUrl?: string; // Add audioUrl
    optionA?: string;
    optionB?: string;
    optionC?: string;
    optionD?: string;
    correctAnswer: string;
    explanation?: string;
    passage?: string;
    passageTranslationData?: string;
    level?: 'A1_A2' | 'B1_B2' | 'C1';
    questionTranslation?: string;
    optionTranslations?: string;
    keyVocabulary?: string;
}

interface Part {
    id: string;
    partNumber: number;
    partName: string;
    instructions?: string;
    totalQuestions: number;
    testId: string;
    audioUrl?: string;
}

const { Option } = Select;
const { Text } = Typography;

const modernShadow = '0 10px 30px -5px rgba(37, 99, 235, 0.08), 0 4px 10px -6px rgba(37, 99, 235, 0.04)';

export default function PartDetail() {
    const { user } = useOutletContext<{ user: User }>();
    const isAdmin = user?.role === 'ADMIN';
    const isSpecialist = user?.role === 'SPECIALIST';
    // const isTeacher = user?.role === 'TEACHER';
    const canManage = isAdmin || isSpecialist;

    const { testId, partId } = useParams<{ testId: string; partId: string }>();
    const navigate = useNavigate();

    const [part, setPart] = useState<Part | null>(null);
    const [questions, setQuestions] = useState<Question[]>([]);
    const [loading, setLoading] = useState(false);
    const [aiLoading, setAiLoading] = useState(false);

    // --- Modal States ---
    const [createModalVisible, setCreateModalVisible] = useState(false);
    const [editModalVisible, setEditModalVisible] = useState(false);
    const [createPart6ModalVisible, setCreatePart6ModalVisible] = useState(false);
    const [createPart7ModalVisible, setCreatePart7ModalVisible] = useState(false);
    const [createPart1ModalVisible, setCreatePart1ModalVisible] = useState(false);
    const [editPart1ModalVisible, setEditPart1ModalVisible] = useState(false);
    const [createPart2ModalVisible, setCreatePart2ModalVisible] = useState(false); // Now for bulk modal
    const [createPart3ModalVisible, setCreatePart3ModalVisible] = useState(false);
    const [createPart5BulkModalVisible, setCreatePart5BulkModalVisible] = useState(false);
    const [part5ImportData, setPart5ImportData] = useState<Record<string, unknown>[]>([]);
    const [part5ImportMode, setPart5ImportMode] = useState<'new' | 'append' | 'replace'>('new'); // Track import mode

    // Passage Edit State
    const [editingGroup, setEditingGroup] = useState<PassageGroup | null>(null);

    // --- Selected Item States ---
    const [editingQuestion, setEditingQuestion] = useState<Question | null>(null);
    const [selectedQuestionIds, setSelectedQuestionIds] = useState<string[]>([]);

    // --- Forms ---
    const [createForm] = Form.useForm();
    const [editForm] = Form.useForm();

    // --- Import States ---
    const [importDrawerVisible, setImportDrawerVisible] = useState(false);


    // --- Quill Configuration ---
    const quillModules = {
        toolbar: [
            ['bold', 'italic', 'underline'],
            [{ 'list': 'ordered' }, { 'list': 'bullet' }],
            ['clean']
        ]
    };

    const quillFormats = [
        'bold', 'italic', 'underline',
        'list', 'bullet'
    ];

    const isPart6 = part?.partNumber === 6;
    const isListeningGroup = part?.partNumber === 3 || part?.partNumber === 4;

    const handleCreateSuccess = () => fetchQuestions();

    // --- Effects ---
    useEffect(() => {
        if (partId) {
            fetchPartDetails();
            fetchQuestions();
        }
    }, [partId]);

    // --- API Fetching ---
    const fetchPartDetails = async () => {
        try {
            const data = await partApi.getDetails(partId!);
            if (data.success) {
                setPart(data.part);
            }
        } catch (error) {
            console.error('Error fetching part details:', error);
        }
    };

    const fetchQuestions = async () => {
        try {
            setLoading(true);
            const data = await partApi.getQuestions(partId!);
            if (data.success) {
                setQuestions(data.questions);
            }
        } catch (error) {
            console.error('Error fetching questions:', error);
        } finally {
            setLoading(false);
        }
    };


    // --- Handlers: Status ---

    const handleEnrichQuestion = async (form: FormInstance) => {
        const values = form.getFieldsValue();
        const { questionText, optionA, optionB, optionC, optionD, correctAnswer } = values;

        if (!questionText || !optionA || !optionB || !optionC || !optionD || !correctAnswer) {
            message.warning('Vui l├▓ng ─æiß╗ün ─æß╗º: C├óu hß╗Åi gß╗æc, ─É├íp ├ín A/B/C/D, v├á ─É├íp ├ín ─æ├║ng tr╞░ß╗¢c khi d├╣ng AI!');
            return;
        }

        setAiLoading(true);
        message.loading({ content: 'AI ─æang ph├ón t├¡ch c├óu hß╗Åi...', key: 'ai-enrich' });

        try {
            const response = await aiApi.enrichPart5Question({
                questionText,
                optionA,
                optionB,
                optionC,
                optionD,
                correctAnswer
            });

            if (response.success && response.data) {
                const aiData = response.data;
                form.setFieldsValue({
                    questionTranslation: aiData.questionTranslation,
                    optionTranslations: aiData.optionTranslations ? JSON.stringify(aiData.optionTranslations, null, 2) : '',
                    explanation: aiData.explanation,
                    keyVocabulary: aiData.keyVocabulary ? JSON.stringify(aiData.keyVocabulary, null, 2) : '',
                    level: aiData.level
                });
                message.success({ content: 'AI ─æ├ú ho├án tß║Ñt ph├ón t├¡ch! Γ£¿', key: 'ai-enrich' });
            } else {
                throw new Error(response.message || 'Lß╗ùi khi gß╗ìi AI');
            }
        } catch (error: unknown) {
            console.error('AI enrich error:', error);
            const errMsg = error instanceof Error ? error.message : 'Kh├┤ng thß╗â ho├án tß║Ñt ph├ón t├¡ch bß║▒ng AI';
            message.error({ content: errMsg, key: 'ai-enrich' });
        } finally {
            setAiLoading(false);
        }
    };

    // --- Handlers: Create ---
    const handleCreateQuestion = async (values: Partial<Question> & Record<string, unknown>) => {
        if (!partId) return;

        // Check for duplicate question number
        const isDuplicate = questions.some(q => q.questionNumber === values.questionNumber);
        if (isDuplicate) {
            message.error(`C├óu sß╗æ ${values.questionNumber} ─æ├ú tß╗ôn tß║íi! Vui l├▓ng chß╗ìn sß╗æ c├óu kh├íc.`);
            return;
        }

        try {
            const data = await questionApi.create(partId, values);
            if (data.success) {
                message.success('Tß║ío c├óu hß╗Åi th├ánh c├┤ng');
                setCreateModalVisible(false);
                createForm.resetFields();
                fetchQuestions();
            } else {
                message.error(data.message || 'Tß║ío c├óu hß╗Åi thß║Ñt bß║íi');
            }
        } catch (error: unknown) {
            console.error('Create error:', error);
            message.error('Lß╗ùi khi tß║ío c├óu hß╗Åi');
        }
    };

    // --- Handlers: Edit ---
    const handleEditQuestion = async (values: Partial<Question> & Record<string, unknown>) => {
        if (!editingQuestion) return;
        try {
            // Normal Update (passage is handled separately now)
            const data = await questionApi.update(editingQuestion.id, values);
            if (data.success) {
                message.success('Cß║¡p nhß║¡t c├óu hß╗Åi th├ánh c├┤ng');
                setQuestions(prev => prev.map(q => q.id === editingQuestion.id ? data.question : q));
                setEditModalVisible(false);
                fetchQuestions();
            } else {
                message.error(data.message || 'Cß║¡p nhß║¡t thß║Ñt bß║íi');
            }
        } catch (error: unknown) {
            console.error('Update error:', error);
            message.error('Lß╗ùi khi cß║¡p nhß║¡t c├óu hß╗Åi');
        }
    };


    // --- Handlers: Delete ---
    const handleDeleteQuestion = async (questionId: string) => {
        const question = questions.find(q => q.id === questionId);
        if (!question) return;

        Modal.confirm({
            title: 'X├íc nhß║¡n x├│a c├óu hß╗Åi',
            content: (
                <div>
                    <p>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a v─⌐nh viß╗àn c├óu hß╗Åi sß╗æ <b>{question.questionNumber}</b>?</p>
                    <p style={{ color: '#DC2626', fontWeight: 600 }}>Cß║óNH B├üO: H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.</p>
                </div>
            ),
            okText: 'X├│a v─⌐nh viß╗àn',
            okType: 'danger',
            cancelText: 'Hß╗ºy',
            onOk: async () => {
                try {
                    const data = await questionApi.delete(questionId);
                    if (data.success) {
                        message.success('─É├ú x├│a c├óu hß╗Åi th├ánh c├┤ng!');
                        fetchQuestions();
                    } else {
                        message.error(data.message || 'Kh├┤ng thß╗â x├│a c├óu hß╗Åi');
                    }
                } catch (error: unknown) {
                    message.error('C├│ lß╗ùi xß║úy ra khi x├│a c├óu hß╗Åi');
                }
            }
        });
    };

    const handleBulkDelete = async () => {
        if (selectedQuestionIds.length === 0) return;

        Modal.confirm({
            title: 'X├íc nhß║¡n x├│a h├áng loß║ít',
            content: (
                <div>
                    <p>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a v─⌐nh viß╗àn <b>{selectedQuestionIds.length}</b> c├óu hß╗Åi ─æ├ú chß╗ìn?</p>
                    <p style={{ color: '#DC2626', fontWeight: 600 }}>Cß║óNH B├üO: H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.</p>
                </div>
            ),
            okText: 'X├│a tß║Ñt cß║ú',
            okType: 'danger',
            cancelText: 'Hß╗ºy',
            onOk: async () => {
                try {
                    const data = await questionApi.deleteBulk(selectedQuestionIds);
                    if (data.success) {
                        message.success(`─É├ú x├│a ${selectedQuestionIds.length} c├óu hß╗Åi th├ánh c├┤ng!`);
                        setSelectedQuestionIds([]);
                        fetchQuestions();
                    } else {
                        message.error(data.message || 'Kh├┤ng thß╗â x├│a c├íc c├óu hß╗Åi ─æ├ú chß╗ìn');
                    }
                } catch (error: unknown) {
                    message.error('C├│ lß╗ùi xß║úy ra khi x├│a h├áng loß║ít');
                }
            }
        });
    };


    // --- Handlers: Audio Upload (Part 1-4) ---
    const handlePartAudioUpload = async (file: File) => {
        if (!partId) return false;
        try {
            message.loading({ content: '─Éang upload audio...', key: 'uploadAudio' });
            const formData = new FormData();
            formData.append('audio', file);

            // 1. Upload to Cloudinary
            const uploadRes = await uploadApi.audio(file);

            if (uploadRes.success) {
                const audioUrl = uploadRes.url;

                // 2. Update Part with new Audio URL
                await partApi.update(partId, { audioUrl });

                message.success({ content: 'Upload audio th├ánh c├┤ng!', key: 'uploadAudio' });
                // Update local part state
                setPart(prev => prev ? { ...prev, audioUrl } : null);
            } else {
                throw new Error(uploadRes.message);
            }
        } catch (error: unknown) {
            console.error('Upload audio error:', error);
            const errMsg = error instanceof Error ? error.message : 'Lß╗ùi khi upload audio';
            message.error({ content: errMsg, key: 'uploadAudio' });
        }
        return false;
    };

    // --- Handlers: Import ---
    const handleDownloadTemplate = () => {
        if (!part) return;
        const partNum = part.partNumber;
        const rows = [];
        const questionCount = partNum === 5 ? 30 : partNum === 6 ? 16 : 10;

        const startNum = partNum === 5 ? 101 : 1;
        const endNum = partNum === 5 ? 130 : (startNum + questionCount - 1);

        for (let i = startNum; i <= endNum; i++) {
            const row: Record<string, string | number> = {
                'Sß╗æ c├óu': i,
                'Nß╗Öi dung c├óu hß╗Åi': '',
                'A': '',
                'B': '',
                'C': '',
                'D': '',
                '─É├íp ├ín ─æ├║ng': ''
            };

            // Only add Passage column for Parts 6 & 7
            if (partNum === 6 || partNum === 7) {
                row['Nß╗Öi dung (Part 6/7)'] = '';
            }

            rows.push(row);
        }

        const worksheet = XLSX.utils.json_to_sheet(rows);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, `Part ${partNum}`);
        XLSX.writeFile(workbook, `Part_${partNum}.xlsx`);
    };

    const handleExcelUpload = async (file: File) => {
        if (!partId) return false;

        const formData = new FormData();
        formData.append('file', file);
        // Removed importMode - no longer used for Part 5

        // --- PART 5 SPECIAL HANDLING: Client-side parsing for Preview ---
        if (part?.partNumber === 5) {
            const reader = new FileReader();
            reader.onload = async (e) => {
                const data = new Uint8Array(e.target?.result as ArrayBuffer);
                const workbook = XLSX.read(data, { type: 'array' });
                const firstSheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[firstSheetName];
                const jsonData = XLSX.utils.sheet_to_json(worksheet);

                // Check existing question count
                try {
                    const data = await partApi.getQuestions(partId!);
                    const existingCount = data.questions?.length || 0;
                    const importCount = jsonData.length;
                    const totalAfterImport = existingCount + importCount;

                    // Determine import mode and show appropriate alert
                    if (existingCount === 0) {
                        // No existing questions - proceed directly
                        setPart5ImportMode('new');
                        setPart5ImportData(jsonData);
                        setCreatePart5BulkModalVisible(true);
                        setImportDrawerVisible(false);
                    } else if (existingCount === 30) {
                        // Already have 30 questions - ask to overwrite
                        Modal.confirm({
                            title: 'Ghi ─æ├¿ c├óu hß╗Åi?',
                            content: `Part 5 ─æ├ú c├│ ─æß╗º 30 c├óu hß╗Åi. Bß║ín c├│ muß╗æn ghi ─æ├¿ to├án bß╗Ö ${existingCount} c├óu c┼⌐ bß║▒ng ${importCount} c├óu mß╗¢i kh├┤ng?`,
                            okText: 'Ghi ─æ├¿',
                            cancelText: 'Hß╗ºy',
                            okButtonProps: { danger: true },
                            onOk: () => {
                                setPart5ImportMode('replace');
                                setPart5ImportData(jsonData);
                                setCreatePart5BulkModalVisible(true);
                                setImportDrawerVisible(false);
                            }
                        });
                    } else if (totalAfterImport > 30) {
                        // Would exceed 30 questions
                        Modal.error({
                            title: 'Kh├┤ng thß╗â import',
                            content: `Kh├┤ng thß╗â import. Tß╗òng sß╗æ c├óu sß║╜ v╞░ß╗út qu├í 30 (${existingCount} + ${importCount} = ${totalAfterImport}). Part 5 chß╗ë ─æ╞░ß╗úc ph├⌐p c├│ tß╗æi ─æa 30 c├óu.`,
                        });
                    } else {
                        // Can append - ask for confirmation
                        Modal.confirm({
                            title: 'Th├¬m c├óu hß╗Åi mß╗¢i?',
                            content: `Part 5 hiß╗çn c├│ ${existingCount} c├óu. Bß║ín c├│ muß╗æn th├¬m ${importCount} c├óu mß╗¢i kh├┤ng? (Tß╗òng: ${totalAfterImport} c├óu)`,
                            okText: 'Th├¬m',
                            cancelText: 'Hß╗ºy',
                            onOk: () => {
                                setPart5ImportMode('append');
                                setPart5ImportData(jsonData);
                                setCreatePart5BulkModalVisible(true);
                                setImportDrawerVisible(false);
                            }
                        });
                    }
                } catch (error) {
                    console.error('Error checking existing questions:', error);
                    message.error('Lß╗ùi khi kiß╗âm tra c├óu hß╗Åi hiß╗çn c├│');
                }
            };
            reader.readAsArrayBuffer(file);
            return false; // Stop upload
        }


        try {
            message.loading({ content: '─Éang import...', key: 'importExcel' });

            // Explicitly use api service (axios) for consistency and auth handling
            const response = await partApi.importQuestions(partId, formData);

            if (response.success) {
                // User requested to see the count
                const count = response.data.count || 0;
                message.success({
                    content: `Import th├ánh c├┤ng! ─É├ú th├¬m ${count} c├óu hß╗Åi.`,
                    key: 'importExcel',
                    duration: 4
                });
                setImportDrawerVisible(false);
                fetchQuestions();
            } else {
                message.error({ content: response.message || 'Import thß║Ñt bß║íi', key: 'importExcel' });
            }
        } catch (error: unknown) {
            console.error('Import error:', error);
            const errMsg = error instanceof Error ? error.message : 'Lß╗ùi kß║┐t nß╗æi khi import';
            message.error({ content: errMsg, key: 'importExcel' });
        }
        return false; // Prevent default auto-upload
    };

    // Removed unused submitImport function since we now upload directly in handleExcelUpload



    // --- Memoized Groups for Part 6/7 ---
    const groups = useMemo(() => {
        if (!questions || questions.length === 0) return [];

        // Sort questions by number
        const sortedQuestions = [...questions].sort((a, b) => a.questionNumber - b.questionNumber);

        // Group by passage (normalized) OR audioUrl (for listening)
        const newGroups: { passage: string; audioUrl?: string; questions: Question[] }[] = [];
        let currentGroup: { passage: string; audioUrl?: string; questions: Question[] } | null = null;

        // Normalization: Remove HTML tags and extra whitespace to compare text content only
        const normalizePassageContent = (p?: string, a?: string) => {
            if (a) return a; // If audio exists, group by audio URL
            if (!p) return '';
            // If passage contains images (Part 7), do not strip tags as the URL differentiates groups
            if (p.includes('<img')) {
                return p.trim();
            }
            const textOnly = p.replace(/<[^>]*>?/gm, ' '); // Replace HTML tags with space
            return textOnly.replace(/\s+/g, ' ').trim();
        };

        sortedQuestions.forEach((q) => {
            const passage = q.passage || '';
            const audioUrl = q.audioUrl;

            const normalizedContent = normalizePassageContent(passage, audioUrl);
            const lastGroupContent = currentGroup ? normalizePassageContent(currentGroup.passage, currentGroup.audioUrl) : '';

            // Group if content matches
            if (!currentGroup || normalizedContent !== lastGroupContent) {
                currentGroup = { passage: passage, audioUrl: audioUrl, questions: [] };
                newGroups.push(currentGroup);
            }
            currentGroup.questions.push(q);
        });
        return newGroups;
    }, [questions]);



    // --- Render Logic: Layouts ---
    const renderGroupedLayout = () => {
        if (!groups || groups.length === 0) return <div style={{ padding: 20, textAlign: 'center', color: '#888' }}>Ch╞░a c├│ c├óu hß╗Åi n├áo</div>;

        return (
            <div style={{ marginTop: 16 }}>
                {groups.map((group, index) => {
                    let aiTranslations: AIPassage[] = [];
                    let vocabulary: VocabularyItem[] = [];
                    let aiQuestionsInfo: AIQuestionInfo[] = [];

                    const firstQ = group.questions[0];
                    if (firstQ?.passageTranslationData) {
                        try {
                            const raw = JSON.parse(firstQ.passageTranslationData);
                            if (Array.isArray(raw)) {
                                aiTranslations = raw;
                            } else {
                                aiTranslations = raw.passages || raw.passageTranslations || [];
                                vocabulary = raw.vocabulary || [];
                                aiQuestionsInfo = raw.questions || [];
                            }
                        } catch (e: unknown) {
                            console.error('Lß╗ùi parse AI translations:', e);
                        }
                    }

                    return (
                        <Card
                            key={index}
                            style={{
                                marginBottom: 32,
                                borderRadius: 24,
                                overflow: 'hidden',
                                boxShadow: modernShadow,
                                border: 'none',
                                background: '#FFFFFF'
                            }}
                            bodyStyle={{ padding: 0 }}
                        >
                            <div style={{
                                padding: '20px',
                                background: '#fff',
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                                        {canManage && (
                                            <Checkbox
                                                checked={group.questions.every(q => selectedQuestionIds.includes(q.id))}
                                                indeterminate={
                                                    group.questions.some(q => selectedQuestionIds.includes(q.id)) &&
                                                    !group.questions.every(q => selectedQuestionIds.includes(q.id))
                                                }
                                                onChange={(e) => {
                                                    const checked = e.target.checked;
                                                    const groupIds = group.questions.map(q => q.id);
                                                    setSelectedQuestionIds(prev => {
                                                        if (checked) {
                                                            const uniqueIdsToAdd = groupIds.filter(id => !prev.includes(id));
                                                            return [...prev, ...uniqueIdsToAdd];
                                                        } else {
                                                            return prev.filter(id => !groupIds.includes(id));
